import { NextRequest, NextResponse } from 'next/server'
import { supabase } from '@/lib/supabase'
import PDFDocument from 'pdfkit'

const normalizeUuidInput = (value: string | null | undefined): string | null => {
  if (
    !value ||
    value === 'undefined' ||
    value === 'null' ||
    value === '' ||
    typeof value !== 'string'
  ) {
    return null
  }
  return value
}

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> | { id: string } }
) {
  try {
    // Handle both async and sync params (Next.js 15+)
    const resolvedParams = params instanceof Promise ? await params : params
    const normalizedId = normalizeUuidInput(resolvedParams?.id)
    
    if (!normalizedId) {
      return NextResponse.json(
        { error: 'Campaign ID is required' },
        { status: 400 }
      )
    }

    // Fetch campaign
    const { data: campaign, error: campaignError } = await supabase
      .from('campaigns')
      .select('*')
      .eq('id', normalizedId)
      .single()

    if (campaignError) throw campaignError
    if (!campaign) {
      return NextResponse.json(
        { error: 'Campaign not found' },
        { status: 404 }
      )
    }

    // Fetch stats
    const { data: statsData } = await supabase.rpc('get_campaign_completion_stats', {
      campaign_uuid: normalizedId
    })
    const stats = statsData && statsData.length > 0 ? statsData[0] : null

    // Fetch agents with progress
    const { data: agentsData } = await supabase
      .from('users')
      .select(`
        id,
        first_name,
        last_name,
        preferred_first_name,
        preferred_last_name,
        email,
        campaign_recipients!inner(
          current_step,
          fully_completed_at
        ),
        campaign_responses(
          commission_plan_2026,
          attending_luncheon,
          luncheon_comments,
          support_rating,
          support_improvements,
          work_preference
        )
      `)
      .eq('status', 'active')
      .contains('roles', ['agent'])
      .eq('campaign_recipients.campaign_id', normalizedId)

    const agents = agentsData || []

    // Fetch RSVPs
    const { data: rsvpData } = await supabase
      .from('campaign_responses')
      .select(`
        *,
        users!inner(
          preferred_first_name,
          preferred_last_name,
          email
        )
      `)
      .eq('campaign_id', normalizedId)
      .not('attending_luncheon', 'is', null)

    const rsvps = rsvpData || []
    const attending = rsvps.filter((r: any) => r.attending_luncheon === true)
    const notAttending = rsvps.filter((r: any) => r.attending_luncheon === false)

    // Fetch survey responses
    const { data: surveyData } = await supabase
      .from('campaign_responses')
      .select(`
        *,
        users!inner(
          preferred_first_name,
          preferred_last_name
        )
      `)
      .eq('campaign_id', normalizedId)
      .not('support_rating', 'is', null)

    const surveys = surveyData || []

    // Generate PDF using buffer approach
    const chunks: Buffer[] = []
    
    const doc = new PDFDocument({ margin: 50, size: 'LETTER' })
    
    doc.on('data', (chunk: Buffer) => {
      chunks.push(chunk)
    })

    // Header
    doc.fontSize(24)
      .text('Campaign Report', { align: 'center' })
    doc.moveDown()
    
    doc.fontSize(16)
      .text(campaign.name, { align: 'center' })
    doc.moveDown(0.5)
    
    doc.fontSize(12).fillColor('#666666')
      .text(`Deadline: ${new Date(campaign.deadline).toLocaleDateString()}`, { align: 'center' })
    doc.moveDown(2)

    // Stats Overview
    if (stats) {
      doc.fontSize(14).fillColor('#000000')
        .text('Overview Statistics')
      doc.moveDown(0.5)
      
      doc.fontSize(11).fillColor('#000000')
      const statsY = doc.y
      doc.text(`Total Recipients: ${stats.total_recipients || 0}`, 50, statsY)
      doc.text(`Fully Completed: ${stats.fully_complete || 0}`, 200, statsY)
      doc.text(`In Progress: ${(stats.total_recipients || 0) - (stats.fully_complete || 0)}`, 350, statsY)
      doc.text(`Attending Luncheon: ${attending.length}`, 50, statsY + 20)
      doc.text(`Not Attending: ${notAttending.length}`, 200, statsY + 20)
      doc.moveDown(2)
    }

    // Agent Progress
    if (agents.length > 0) {
      doc.fontSize(14).fillColor('#000000')
        .text('Agent Progress')
      doc.moveDown(0.5)

      // Table header
      const tableTop = doc.y
      doc.fontSize(10)
      doc.text('Agent Name', 50, tableTop)
      doc.text('Email', 200, tableTop)
      doc.text('Progress', 350, tableTop)
      doc.text('Commission Plan', 450, tableTop)
      doc.text('RSVP', 550, tableTop)
      
      // Draw line under header
      doc.moveTo(50, tableTop + 15)
        .lineTo(550, tableTop + 15)
        .stroke()
      
      let currentY = tableTop + 25

      agents.forEach((agent: any) => {
        if (currentY > 700) {
          doc.addPage()
          currentY = 50
        }

        const recipient = agent.campaign_recipients?.[0]
        const response = agent.campaign_responses?.[0]
        const progress = recipient?.current_step || 0
        const isComplete = recipient?.fully_completed_at
        const progressText = isComplete ? 'Complete' : `Step ${progress}/4`
        const commissionPlan = response?.commission_plan_2026 || '-'
        const rsvpStatus = response?.attending_luncheon === true 
          ? 'Attending' 
          : response?.attending_luncheon === false 
            ? 'Not Attending' 
            : '-'

        doc.fontSize(9)
        doc.text(`${agent.preferred_first_name} ${agent.preferred_last_name}`, 50, currentY)
        doc.text(agent.email, 200, currentY, { width: 140 })
        doc.text(progressText, 350, currentY)
        doc.text(commissionPlan, 450, currentY, { width: 90 })
        doc.text(rsvpStatus, 550, currentY, { width: 50 })

        currentY += 20
      })

      doc.moveDown(2)
    }

    // RSVP Details
    if (attending.length > 0) {
      doc.addPage()
      doc.fontSize(14).fillColor('#000000')
        .text(`Luncheon RSVPs (${attending.length} attending)`)
      doc.moveDown(0.5)

      attending.forEach((rsvp: any) => {
        if (doc.y > 700) {
          doc.addPage()
        }

        doc.fontSize(11)
          .text(`${rsvp.users.preferred_first_name} ${rsvp.users.preferred_last_name}`)
        if (rsvp.luncheon_comments) {
          doc.fontSize(10).fillColor('#666666')
            .text(`"${rsvp.luncheon_comments}"`, { indent: 20 })
        }
        doc.moveDown(0.5)
      })
      doc.moveDown()
    }

    // Feedback Survey Summary
    if (surveys.length > 0) {
      if (doc.y > 600) {
        doc.addPage()
      }

      doc.fontSize(14).fillColor('#000000')
        .text(`Feedback Survey Summary (${surveys.length} responses)`)
      doc.moveDown(0.5)

      // Average Support Rating
      const avgRating = surveys.reduce((sum: number, s: any) => sum + (s.support_rating || 0), 0) / surveys.length
      if (avgRating > 0) {
        doc.fontSize(11)
          .text('Average Support Rating')
        doc.fontSize(11)
          .text(`${avgRating.toFixed(1)}/10`)
        doc.moveDown()
      }

      // Work Preference Breakdown
      const teamCount = surveys.filter((s: any) => s.work_preference === 'team').length
      const independentCount = surveys.filter((s: any) => s.work_preference === 'independent').length
      const notSureCount = surveys.filter((s: any) => s.work_preference === 'not_sure').length

      if (teamCount > 0 || independentCount > 0 || notSureCount > 0) {
        doc.fontSize(11)
          .text('Work Preference')
        doc.fontSize(11)
        doc.text(`Team: ${teamCount}`, { indent: 20 })
        doc.text(`Independent: ${independentCount}`, { indent: 20 })
        doc.text(`Not Sure: ${notSureCount}`, { indent: 20 })
        doc.moveDown()
      }

      // Support Improvement Suggestions
      const improvements = surveys.filter((s: any) => s.support_improvements)
      if (improvements.length > 0) {
        doc.fontSize(11)
          .text('Support Improvement Suggestions')
        doc.moveDown(0.3)

        improvements.forEach((survey: any) => {
          if (doc.y > 700) {
            doc.addPage()
          }

          doc.fontSize(10)
            .text(`${survey.users.preferred_first_name} ${survey.users.preferred_last_name}:`)
          doc.fontSize(10).fillColor('#666666')
            .text(`"${survey.support_improvements}"`, { indent: 20 })
          doc.moveDown(0.5)
        })
      }
    }

    // Footer
    doc.fontSize(8).fillColor('#999999')
      .text(
        `Generated on ${new Date().toLocaleString()}`,
        50,
        doc.page.height - 50,
        { align: 'center' }
      )

    // Finalize PDF and get buffer
    const pdfBuffer = await new Promise<Buffer>((resolve, reject) => {
      doc.on('end', () => {
        resolve(Buffer.concat(chunks))
      })
      doc.on('error', reject)
      doc.end()
    })

    // Return PDF
    return new NextResponse(pdfBuffer, {
      headers: {
        'Content-Type': 'application/pdf',
        'Content-Disposition': `attachment; filename="campaign-report-${campaign.name.replace(/[^a-z0-9]/gi, '-').toLowerCase()}-${new Date().toISOString().split('T')[0]}.pdf"`,
      },
    })
  } catch (error: any) {
    console.error('PDF export error:', error)
    console.error('Error stack:', error?.stack)
    return NextResponse.json(
      { 
        error: error?.message || 'Failed to generate PDF report',
        details: process.env.NODE_ENV === 'development' ? error?.stack : undefined
      },
      { status: 500 }
    )
  }
}
